t.script:
(function(){
  function clean(){
    ['header#top','#top','.tp-custom-header','.tp-preheader',
     '.tp-bottombar-component','footer','.o_footer',
     '[data-name="Header"]','[data-name="Footer"]',
     '#top_menu_collapse_mobile'].forEach(function(sel){
      document.querySelectorAll(sel).forEach(function(el){ el.remove(); });
    });
    document.body.style.paddingTop = '0';
    var w = document.getElementById('wrapwrap');
    if(w){ w.style.paddingTop = '0'; }
  }
  clean();
  document.addEventListener('DOMContentLoaded', clean);
  window.addEventListener('load', clean);
  setTimeout(clean, 500);
  setTimeout(clean, 1500);
})();

(function(){
  function rm(){
    document.querySelectorAll('header,header#top,.tp-custom-header,.tp-preheader,.tp-bottombar-component,footer,.o_footer,[data-name="Header"],[data-name="Footer"],#top_menu_collapse_mobile').forEach(function(e){e.remove();});
    document.body.style.cssText += 'padding:0!important;margin:0!important;';
    var w=document.getElementById('wrapwrap');if(w)w.style.cssText+='padding:0!important;';
  }
  rm();
  document.addEventListener('DOMContentLoaded',rm);
  window.addEventListener('load',rm);
  setTimeout(rm,300);setTimeout(rm,800);setTimeout(rm,2000);
})();

(function(){
  var sidebarOpen = window.innerWidth > 768;
  var notifOpen = false;
  var refreshSec = 30;
  var remaining = refreshSec;

  // Init sidebar on mobile
  if(window.innerWidth <= 768){
    var sb2=document.getElementById('vp-sidebar');
    var mn=document.getElementById('vp-main');
    if(sb2)sb2.style.transform='translateX(-100%)';
    if(mn)mn.style.marginLeft='0';
  }
  var vov=document.createElement('div');
  vov.id='vp-ov';vov.style.cssText='display:none;position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:800;';
  vov.onclick=function(){if(sidebarOpen)window.vpToggleSidebar();};
  document.body.appendChild(vov);
  // Init sidebar on mobile
  if(window.innerWidth <= 768){
    var sb = document.getElementById('vp-sidebar');
    var main = document.getElementById('vp-main');
    if(sb) sb.style.transform = 'translateX(-100%)';
    if(main) main.style.marginLeft = '0';
  }
  // Overlay for mobile
  var ov = document.createElement('div');
  ov.id = 'vp-ov';
  ov.style.cssText = 'display:none;position:fixed;inset:0;background:rgba(0,0,0,.4);z-index:800;';
  ov.onclick = function(){ if(sidebarOpen) window.vpToggleSidebar(); };
  document.body.appendChild(ov);

  window.vpToggleSidebar = function(){
    var sb = document.getElementById('vp-sidebar');
    var main = document.getElementById('vp-main');
    var h1 = document.getElementById('vph1');
    var h2 = document.getElementById('vph2');
    var h3 = document.getElementById('vph3');
    sidebarOpen = !sidebarOpen;
    var overlay = document.getElementById('vp-ov');
    if(sidebarOpen){
      sb.style.transform = '';
      if(window.innerWidth > 768) main.style.marginLeft = '220px';
      else if(overlay) overlay.style.display = 'block';
      if(h1){ h1.style.transform=''; h2.style.opacity='1'; h3.style.transform=''; }
    } else {
      sb.style.transform = 'translateX(-100%)';
      if(window.innerWidth > 768) main.style.marginLeft = '0';
      if(overlay) overlay.style.display = 'none';
      if(h1){ h1.style.transform='rotate(45deg) translate(4px,4px)'; h2.style.opacity='0'; h3.style.transform='rotate(-45deg) translate(4px,-4px)'; }
    }
  };

  window.vpToggleNotif = function(){
    notifOpen = !notifOpen;
    var panel = document.getElementById('vp-notif-panel');
    if(panel) panel.classList.toggle('open', notifOpen);
  };

  window.vpClearNotif = function(){
    document.querySelectorAll('.vp-notif-item.unread').forEach(function(i){ i.classList.remove('unread'); });
    var dot = document.getElementById('vp-notif-dot');
    var badge = document.getElementById('vp-notif-badge');
    if(dot) dot.classList.remove('show');
    if(badge) badge.style.display = 'none';
  };

          if(notifOpen) window.vpToggleNotif();
    }
  });
})();

function loadNotifs(){
  fetch('/my/vendor/notifications/poll',{headers:{'X-Requested-With':'XMLHttpRequest'}})
  .then(function(r){return r.json();})
  .then(function(data){
    var list = document.getElementById('notif-list');
    if(!list) return;
    if(!data.items || data.items.length === 0){
      list.innerHTML = '<div style="text-align:center;padding:48px;color:#aaa"><i class="fa fa-bell fa-2x" style="display:block;margin-bottom:8px;opacity:.2"></i>No notifications yet</div>';
      return;
    }
    list.innerHTML = data.items.map(function(item){
      return '<div class="vp-notif-item unread" style="padding:14px 16px;border-bottom:1px solid #f5f5f5;display:flex;gap:10px;align-items:flex-start">'+
        '<div style="width:36px;height:36px;border-radius:8px;background:'+item.bg+';color:'+item.color+';display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="fa '+item.icon+'"></i></div>'+
        '<div style="flex:1"><div style="font-weight:600;font-size:13px">'+item.title+'</div><div style="font-size:12px;color:#888;margin-top:2px">'+item.body+'</div></div>'+
        '<span style="font-size:11px;color:#aaa;flex-shrink:0">'+item.time+'</span>'+
      '</div>';
    }).join('');
  }).catch(function(){});
}
function clearNotifs(){
  var dot = document.getElementById('vp-notif-dot');
  if(dot) dot.classList.remove('show');
  var list = document.getElementById('notif-list');
  if(list) list.innerHTML = '<div style="text-align:center;padding:48px;color:#aaa">No notifications</div>';
}
loadNotifs();
